```java
import org.springframework.kafka.annotation.*;
import org.springframework.retry.annotation.Backoff;
import org.springframework.stereotype.Service;

@Service
public class TradeNotificationConsumer {
    private final SmsService smsService;
    TradeNotificationConsumer(SmsService s) { smsService = s; }

    @RetryableTopic(attempts = "3",
                    backoff = @Backoff(delay = 500, multiplier = 2.0))
    @KafkaListener(topics = "trade-executed",
                   groupId = "notification-group")
    public void handleTrade(TradeExecutedEvent event) {
        smsService.send(event.userId(),
            String.format("Trade: %d %s @ ₹%.2f",
                event.qty(), event.symbol(), event.price()));
    }

    @DltHandler
    public void handleFailedTrade(TradeExecutedEvent event) {
        System.err.println("TRADE NOTIFICATION FAILED (DLT): " + event.tradeId());
        // save to failed_notifications table for ops team
    }
}
```

