    "spring.kafka.consumer.auto-offset-reset=earliest"
})
class TradeNotificationConsumerTest {
    @Autowired KafkaTemplate<String,TradeExecutedEvent> kafkaTemplate;
    @MockBean SmsService smsService;

    @Test void handleTrade_callsSmsService() throws Exception {
        var event = new TradeExecutedEvent(
            "TRD-001","U01","TCS",10,3890.0,38900.0,"BUY",Instant.now());
        kafkaTemplate.send("trade-executed", event.symbol(), event);

        // Wait for listener to process:
        Thread.sleep(2000);
        verify(smsService, times(1)).send(eq("U01"), contains("TCS"));
    }
}
